    <line x1="60" y1="70" x2="60" y2="460" stroke="#3f3f46" stroke-width="2"/>
    <circle cx="60" cy="95" r="7" fill="#f59e0b"/>
    <text x="90" y="85" fill="#f59e0b" font-weight="700" font-size="14" font-family="sans-serif">Ab 2019</text>
    <text x="90" y="107" fill="#a1a1aa" font-size="13" font-family="sans-serif">Jump kauft Luna angeblich unter Marktpreis, geheime Deals</text>
